import{_ as s,o as e,c as a,ae as t}from"./chunks/framework.BMBGeRFM.js";const k=JSON.parse('{"title":"Errors and Compiling","description":"","frontmatter":{},"headers":[],"relativePath":"conventions/errors-and-compiling/index.md","filePath":"conventions/errors-and-compiling/index.md"}'),n={name:"conventions/errors-and-compiling/index.md"};function o(r,i,l,d,p,h){return e(),a("div",null,[...i[0]||(i[0]=[t('<h1 id="errors-and-compiling" tabindex="-1">Errors and Compiling <a class="header-anchor" href="#errors-and-compiling" aria-label="Permalink to &quot;Errors and Compiling&quot;">​</a></h1><h2 id="panicking-vs-try-color" tabindex="-1">Panicking vs <code>try_color()</code> <a class="header-anchor" href="#panicking-vs-try-color" aria-label="Permalink to &quot;Panicking vs `try_color()`&quot;">​</a></h2><p><code>color()</code>, <code>cprintln!()</code>, and friends all panic on invalid markup. That&#39;s fine for most cases where you wrote the markup yourself and you know it&#39;s valid.</p><div class="language-rust vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cprintln!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[bold green]All good here.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>Switch to <code>try_color()</code> when the markup comes from somewhere you don&#39;t fully control, like user input, a config file, or a database.</p><div class="language-rust vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">match</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> try_color</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">user_input) {</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    Ok</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(s) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> println!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;{s}&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    Err</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(e) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> eprintln!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Invalid markup: {e}&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Never use <code>color()</code> on unvalidated external input. A bad tag will panic your whole program.</p></div><h2 id="the-compile-feature" tabindex="-1">The <code>compile</code> Feature <a class="header-anchor" href="#the-compile-feature" aria-label="Permalink to &quot;The `compile` Feature&quot;">​</a></h2><p>Enable it when your markup is all fixed string literals and you want two things: zero runtime parsing overhead, and compile-time errors instead of runtime panics.</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">farben = { version = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;x.x.x&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, features = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;compile&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] }</span></span></code></pre></div><p>With <code>compile</code> enabled, <code>color!(&quot;[red]hello&quot;)</code> becomes a string literal baked into your binary at compile time. Invalid markup becomes a compiler error -- not a surprise at runtime.</p><div class="language-rust vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">color!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[notacolor]oops&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// compiler error, not a panic</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>The <code>compile</code> feature only eliminates overhead for <code>color!()</code> with fixed strings. <code>color_fmt!()</code>, <code>cprintln!()</code>, and <code>cprint!()</code> still run at runtime, but their format strings are validated at compile time.</p></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>As of 0.4.0, every interface other than <code>color_fmt!()</code> and <code>try_color()</code> now has full compile-time parsing for static strings, eliminating runtime overhead. Long live compilers!</p></div><p>Skip the <code>compile</code> feature if most of your markup is dynamic or comes from runtime values. The validation benefit is still there for format strings, but the binary size tradeoff may not be worth it for smaller projects.</p><h2 id="markdown-and-errors" tabindex="-1">Markdown and Errors <a class="header-anchor" href="#markdown-and-errors" aria-label="Permalink to &quot;Markdown and Errors&quot;">​</a></h2><p>Markdown plays by different rules -- <code>markdown()</code>, <code>mdprint!()</code>, and friends <strong>never panic and never return errors</strong>. Unclosed or unrecognized delimiters are silently treated as plain text, the same way a real Markdown renderer would handle them.</p><div class="language-rust vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// This is fine -- no closing **, treated as plain text</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mdprintln!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;**oops no closing delimiter&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>This means there is no <code>try_markdown()</code> -- it would never return an <code>Err</code>. If you&#39;re processing external input and want to render it as markdown, just call <code>markdown()</code> directly with no error handling needed.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Combine <code>try_color()</code> and <code>markdown()</code> when you need both -- validate the farben markup first, then render any markdown in the result.</p></div>',20)])])}const u=s(n,[["render",o]]);export{k as __pageData,u as default};
